mapper.sql:
(
  (e.visibility = 'public' AND e.status = 'published')
  OR e.creator_user_id = #{userId}
  OR EXISTS (
    SELECT 1
    FROM event_participants ep_access
    WHERE ep_access.event_id = e.id
      AND ep_access.user_id = #{userId}
      AND ep_access.status IN ('joined', 'approved', 'waitlisted')
  )
)

mapper.select:
SELECT , , ep.status AS user_participant_status FROM events e LEFT JOIN event_participants ep ON ep.event_id = e.id AND ep.user_id = #{userId} WHERE e.visibility = 'public' AND e.status = 'published'
AND e.start_at >= #{from}
AND e.start_at < #{to}
AND ( e.title_hr ILIKE '%' || #{query} || '%' OR e.title_en ILIKE '%' || #{query} || '%' OR e.where_hr ILIKE '%' || #{query} || '%' OR e.where_en ILIKE '%' || #{query} || '%' OR e.address ILIKE '%' || #{query} || '%' OR e.about_hr ILIKE '%' || #{query} || '%' OR e.about_en ILIKE '%' || #{query} || '%' )
AND <= #{radiusKm}
ORDER BY
ASC,
e.start_at ASC

SELECT , , ep.status AS user_participant_status FROM events e LEFT JOIN event_participants ep ON ep.event_id = e.id AND ep.user_id = #{userId} WHERE e.visibility = 'public' AND e.status = 'published'
AND ( e.start_at < #{cursorStartAt} OR (e.start_at = #{cursorStartAt} AND e.id < #{cursorId}) )
ORDER BY e.start_at DESC, e.id DESC LIMIT #{limit}

SELECT id, event_id, media_type, url, thumbnail_url, sort_order FROM event_media WHERE event_id IN
#{eventId}
ORDER BY event_id ASC, sort_order ASC, created_at ASC

mapper.insert:
INSERT INTO event_likes (
  event_id,
  user_id
) VALUES (
  #{eventId},
  #{userId}
)
ON CONFLICT (event_id, user_id) DO NOTHING

mapper.delete:
DELETE FROM event_likes
WHERE event_id = #{eventId}
  AND user_id = #{userId}

mapper.update:
UPDATE events
SET organizer_rating_average = COALESCE((
      SELECT ROUND(AVG(rating)::NUMERIC, 2)
      FROM event_organizer_ratings
      WHERE event_id = #{eventId}
    ), 0),
    organizer_rating_count = (
      SELECT COUNT(*)::INTEGER
      FROM event_organizer_ratings
      WHERE event_id = #{eventId}
    ),
    updated_at = NOW()
WHERE id = #{eventId}
